mapper.select:
SELECT id, departure_time, arrival_time, duration_minutes, effective_date,
       flight_number, airline_code, cabin_class, aircraft_type, stops, is_direct,
       departure_airport, arrival_airport, departure_airport_code, arrival_airport_code,
       price, original_price, available_seats, status, created_at, updated_at
FROM flight
WHERE departure_airport_code = #{departureAirportCode}
  AND arrival_airport_code = #{arrivalAirportCode}
  AND effective_date = #{effectiveDate}

SELECT id, departure_time, arrival_time, duration_minutes, effective_date,
       flight_number, airline_code, cabin_class, aircraft_type, stops, is_direct,
       departure_airport, arrival_airport, departure_airport_code, arrival_airport_code,
       price, original_price, available_seats, status, created_at, updated_at
FROM flight


        AND departure_airport_code = #{departureAirportCode}


        AND arrival_airport_code = #{arrivalAirportCode}


        AND effective_date = #{effectiveDate}


        AND cabin_class = #{cabinClass}


        AND airline_code = #{airlineCode}


        AND is_direct = TRUE


        AND stops <= #{maxStops}

    AND status = 'SCHEDULED'



        ORDER BY price ASC, departure_time ASC


        ORDER BY price DESC, departure_time ASC


        ORDER BY duration_minutes ASC, price ASC


        ORDER BY departure_time ASC, price ASC



        ORDER BY (price * 0.6 + duration_minutes * 2) ASC, departure_time ASC


        ORDER BY price ASC, departure_time ASC
